class Solution:
    def canTransform(self, start: str, result: str) -> bool:
        if start.replace('X', '') != result.replace('X', ''):
            return False

        start_l, result_l = [], []
        for i, c in enumerate(start):
            if c == 'L':
                start_l.append(i)
        for i, c in enumerate(result):
            if c == 'L':
                result_l.append(i)

        for s, r in zip(start_l, result_l):
            if s < r:
                return False

        start_r, result_r = [], []
        for i, c in enumerate(start):
            if c == 'R':
                start_r.append(i)
        for i, c in enumerate(result):
            if c == 'R':
                result_r.append(i)

        for s, r in zip(start_r, result_r):
            if s > r:
                return False

        return True
